solution_code:
#include <iostream>

int sumArray(const int* arr, int count) {
    int total = 0;
    for (int i = 0; i < count; ++i) {
        total += arr[i];
    }
    return total;
}

int main() {
    int n{};
    std::cin >> n;

    int data[15]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    std::cout << "Sum: " << sumArray(data, n) << '\n';
    return 0;
}

