#include <iostream>

int countPositives(const int* arr, int count) {
    int total = 0;
    for (int i = 0; i < count; ++i) {
        if (arr[i] > 0)
            ++total;
    }
    return total;
}

int main() {
    int n{};
    std::cin >> n;

    int data[10]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    std::cout << "Positives: " << countPositives(data, n) << '\n';
    return 0;
}
